CREATE TABLE IF NOT EXISTS communication.communications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid REFERENCES valora.organizations(id), survey_id uuid REFERENCES valora.surveys(id), response_id uuid REFERENCES valora.responses(id), channel text NOT NULL, event_type text NOT NULL, status text NOT NULL DEFAULT 'pending', recipient_masked text, provider_message_id text, attempts int NOT NULL DEFAULT 0, last_error text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), sent_at timestamptz);
